def pagerank_step(nodes, pr_scores, d=0.85):
    new_scores = {}
    num_nodes = len(nodes)
    for node in nodes:
        rank_sum = 0
        # Find all neighbors pointing to this node
        for neighbor, links in nodes.items():
            if node in links:
                rank_sum += pr_scores[neighbor] / len(links)

        new_scores[node] = round((1 - d) + d * rank_sum, 3)
    return new_scores

# Graph: A->B,C; B->C; C->A
web_graph = {'A': ['B', 'C'], 'B': ['C'], 'C': ['A']}
scores = {'A': 1.0, 'B': 1.0, 'C': 1.0}

for i in range(3):
    scores = pagerank_step(web_graph, scores)
    print(f"Iteration {i+1}: {scores}")
